import React, { useEffect, useState } from 'react';
import { useParams, Link } from 'react-router-dom';
import { getArtiste } from '../api/artisteService';
import { getAlbums } from '../api/albumService';

export default function ArtisteDetail() {
  const { id } = useParams();
  const [artiste, setArtiste] = useState(null);
  const [albums, setAlbums] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    setLoading(true);
    Promise.all([getArtiste(id), getAlbums()])
      .then(([artisteRes, albumsRes]) => {
        setArtiste(artisteRes.data || null);
        setAlbums((albumsRes.data || []).filter((album) => album.artisteId === parseInt(id, 10)));
      })
      .catch(() => {
        setArtiste(null);
        setAlbums([]);
      })
      .finally(() => setLoading(false));
  }, [id]);

  if (loading) return <div className="alert alert-secondary">Chargement...</div>;
  if (!artiste) return <div className="alert alert-danger">Artiste non trouvé.</div>;

  return (
    <div>
      <div className="mb-4">
        <h1 className="h3">{artiste.nom}</h1>
        <p className="text-muted mb-1">ID: {artiste.id}</p>
        {artiste.image && (
          <img
            src={`/uploads/images/${artiste.image}`}
            alt={artiste.nom}
            className="img-fluid rounded mb-3"
            style={{ maxWidth: 220 }}
          />
        )}
        <p>{artiste.description || 'Aucune description fournie.'}</p>
        <div className="d-flex gap-2">
          <Link className="btn btn-outline-primary" to={`/artistes/${id}/edit`}>
            Modifier l'artiste
          </Link>
          <Link className="btn btn-secondary" to="/artistes">
            Retour à la liste
          </Link>
        </div>
      </div>

      <div className="card border-0 shadow-sm">
        <div className="card-body">
          <h5 className="card-title">Albums liés</h5>
          {albums.length === 0 ? (
            <p className="text-muted">Cet artiste n'a pas encore d'albums enregistrés.</p>
          ) : (
            <ul className="list-group list-group-flush">
              {albums.map((album) => (
                <li key={album.id} className="list-group-item d-flex justify-content-between align-items-center">
                  <div>
                    <Link to={`/albums/${album.id}`} className="fw-semibold">
                      {album.titre}
                    </Link>
                    <div className="small text-muted">Album ID: {album.id}</div>
                  </div>
                  <span className="badge bg-primary rounded-pill">{album.image ? 'Image' : 'Sans image'}</span>
                </li>
              ))}
            </ul>
          )}
        </div>
      </div>
    </div>
  );
}
